mapper.select:
select distinct m.* from sys_menu m inner join sys_role_menu rm on rm.menu_id = m.menu_id and rm.deleted = 0 where rm.role_id in
#{roleId}
and m.deleted = 0 and m.status = 'ENABLED' order by m.sort_no asc, m.menu_id asc

select distinct m.permission_code from sys_menu m inner join sys_role_menu rm on rm.menu_id = m.menu_id and rm.deleted = 0 where rm.role_id in
#{roleId}
and m.deleted = 0 and m.permission_code is not null and m.permission_code <> ''
